contracts/identity/DIDRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "../tokens/WorkToken.sol";

/**
 * @title DIDRegistry
 * @notice ERC-1056 inspired DID registry for Lobster Agents.
 *         DID format: did:ethr:qan:<address>
 *         Registration requires staking WORK tokens as Sybil defense.
 */
contract DIDRegistry is AccessControl, Pausable {
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
    bytes32 public constant SLASHER_ROLE = keccak256("SLASHER_ROLE");

    uint256 public constant MIN_STAKE = 100 * 1e18;

    WorkToken public immutable workToken;

    struct DIDRecord {
        bool active;
        uint256 stakedAmount;
        uint256 registeredAt;
        uint256 creditScore;
        string controller;
    }

    mapping(address => DIDRecord) public dids;
    mapping(address => address) public delegates;
    uint256 public totalActiveDIDs;

    event DIDRegistered(address indexed agent, uint256 stake, uint256 timestamp);
    event DIDRevoked(address indexed agent, uint256 stakeReturned);
    event DelegateChanged(address indexed identity, address indexed delegate, uint256 validity);
    event AttributeChanged(address indexed identity, bytes32 indexed name, bytes value, uint256 validity);
    event CreditUpdated(address indexed agent, int256 delta, uint256 newScore);

    constructor(address workToken_, address admin) {
        workToken = WorkToken(workToken_);
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(PAUSER_ROLE, admin);
        _grantRole(SLASHER_ROLE, admin);
    }

    function registerDID(uint256 stakeAmount) external whenNotPaused {
        require(!dids[msg.sender].active, "DID already registered");
        require(stakeAmount >= MIN_STAKE, "Stake below minimum");

        workToken.transferFrom(msg.sender, address(this), stakeAmount);

        dids[msg.sender] = DIDRecord({
            active: true,
            stakedAmount: stakeAmount,
            registeredAt: block.timestamp,
            creditScore: 100,
            controller: ""
        });
        totalActiveDIDs++;

        emit DIDRegistered(msg.sender, stakeAmount, block.timestamp);
    }

    function revokeDID() external whenNotPaused {
        DIDRecord storage record = dids[msg.sender];
        require(record.active, "DID not active");

        uint256 stakeToReturn = record.stakedAmount;
        record.active = false;
        record.stakedAmount = 0;
        totalActiveDIDs--;

        workToken.transfer(msg.sender, stakeToReturn);
        emit DIDRevoked(msg.sender, stakeToReturn);
    }

    function isValid(address agent) external view returns (bool) {
        return dids[agent].active;
    }

    function getStake(address agent) external view returns (uint256) {
        return dids[agent].stakedAmount;
    }

    function getCreditScore(address agent) external view returns (uint256) {
        return dids[agent].creditScore;
    }

    function updateCredit(address agent, int256 delta) external onlyRole(SLASHER_ROLE) {
        DIDRecord storage record = dids[agent];
        require(record.active, "DID not active");

        uint256 current = record.creditScore;
        if (delta < 0 && uint256(-delta) >= current) {
            record.creditScore = 0;
        } else if (delta < 0) {
            record.creditScore = current - uint256(-delta);
        } else {
            record.creditScore = current + uint256(delta);
        }

        emit CreditUpdated(agent, delta, record.creditScore);
    }

    function slashStake(address agent, uint256 basisPoints, string calldata reason)
        external
        onlyRole(SLASHER_ROLE)
    {
        DIDRecord storage record = dids[agent];
        require(record.active, "DID not active");

        uint256 slashAmount = (record.stakedAmount * basisPoints) / 10000;
        record.stakedAmount -= slashAmount;
        workToken.slash(address(this), slashAmount, reason);
    }

    function setDelegate(address identity, address delegate, uint256 validity) external {
        require(msg.sender == identity, "Not identity owner");
        delegates[identity] = delegate;
        emit DelegateChanged(identity, delegate, validity);
    }

    function setAttribute(bytes32 name, bytes calldata value, uint256 validity) external {
        require(dids[msg.sender].active, "DID not active");
        emit AttributeChanged(msg.sender, name, value, validity);
    }

    function pause() external onlyRole(PAUSER_ROLE) { _pause(); }
    function unpause() external onlyRole(PAUSER_ROLE) { _unpause(); }
}

contracts/market/TaskMarket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "../tokens/WorkToken.sol";
import "../identity/DIDRegistry.sol";

/**
 * @title TaskMarket
 * @notice Code task marketplace. Clients post tasks with WORK escrow.
 *         Lobster Agents (valid DID) accept and submit results.
 *         Verification is delegated to AuditVoting contract.
 */
contract TaskMarket is AccessControl, Pausable, ReentrancyGuard {
    bytes32 public constant REVIEWER_ROLE = keccak256("REVIEWER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");

    WorkToken public immutable workToken;
    DIDRegistry public immutable didRegistry;

    enum TaskStatus { Pending, Active, Submitted, Verified, Disputed, Settled, Cancelled }

    struct Task {
        address client;
        address assignee;
        uint256 reward;
        uint256 postedAt;
        uint256 deadline;
        TaskStatus status;
        string descriptionHash;
        string resultHash;
    }

    uint256 public taskCount;
    mapping(uint256 => Task) public tasks;

    uint256 public constant AUDIT_FEE_BPS = 500;    // 5% to audit agents
    uint256 public constant TREASURY_BPS = 2000;     // 20% to treasury
    uint256 public constant GOV_SHARE_BPS = 1000;    // 10% to GOV holders
    uint256 public constant CONTRIBUTOR_BPS = 7000;  // 70% to contributor

    address public treasury;

    event TaskPosted(uint256 indexed taskId, address indexed client, uint256 reward, string descHash);
    event TaskAccepted(uint256 indexed taskId, address indexed agent);
    event TaskSubmitted(uint256 indexed taskId, address indexed agent, string resultHash);
    event TaskVerified(uint256 indexed taskId, address indexed agent, uint256 payout);
    event TaskDisputed(uint256 indexed taskId);
    event TaskSettled(uint256 indexed taskId, bool agentPaid);
    event TaskCancelled(uint256 indexed taskId);

    constructor(address workToken_, address didRegistry_, address treasury_, address admin) {
        workToken = WorkToken(workToken_);
        didRegistry = DIDRegistry(didRegistry_);
        treasury = treasury_;
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(PAUSER_ROLE, admin);
        _grantRole(REVIEWER_ROLE, admin);
    }

    function postTask(uint256 reward, uint256 deadline, string calldata descHash)
        external
        whenNotPaused
        nonReentrant
        returns (uint256 taskId)
    {
        require(reward > 0, "Reward must be positive");
        require(deadline > block.timestamp, "Deadline must be future");

        workToken.transferFrom(msg.sender, address(this), reward);

        taskId = ++taskCount;
        tasks[taskId] = Task({
            client: msg.sender,
            assignee: address(0),
            reward: reward,
            postedAt: block.timestamp,
            deadline: deadline,
            status: TaskStatus.Pending,
            descriptionHash: descHash,
            resultHash: ""
        });

        emit TaskPosted(taskId, msg.sender, reward, descHash);
    }

    function acceptTask(uint256 taskId) external whenNotPaused nonReentrant {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Pending, "Task not available");
        require(didRegistry.isValid(msg.sender), "Invalid DID");
        require(block.timestamp < task.deadline, "Task expired");

        task.assignee = msg.sender;
        task.status = TaskStatus.Active;

        emit TaskAccepted(taskId, msg.sender);
    }

    function submitResult(uint256 taskId, string calldata resultHash)
        external
        whenNotPaused
    {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Active, "Task not active");
        require(task.assignee == msg.sender, "Not task assignee");

        task.resultHash = resultHash;
        task.status = TaskStatus.Submitted;

        emit TaskSubmitted(taskId, msg.sender, resultHash);
    }

    function verifyTask(uint256 taskId, bool passed)
        external
        onlyRole(VERIFIER_ROLE)
        nonReentrant
    {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Submitted, "Task not submitted");

        if (passed) {
            task.status = TaskStatus.Verified;
            _distributeReward(taskId);
        } else {
            task.status = TaskStatus.Disputed;
            emit TaskDisputed(taskId);
        }
    }

    function settleDispute(uint256 taskId, bool agentPaid)
        external
        onlyRole(REVIEWER_ROLE)
        nonReentrant
    {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Disputed, "Task not disputed");

        task.status = TaskStatus.Settled;

        if (agentPaid) {
            _distributeReward(taskId);
        } else {
            workToken.transfer(task.client, task.reward);
        }

        emit TaskSettled(taskId, agentPaid);
    }

    function cancelTask(uint256 taskId) external nonReentrant {
        Task storage task = tasks[taskId];
        require(task.client == msg.sender, "Not task client");
        require(task.status == TaskStatus.Pending, "Cannot cancel");

        task.status = TaskStatus.Cancelled;
        workToken.transfer(task.client, task.reward);

        emit TaskCancelled(taskId);
    }

    function _distributeReward(uint256 taskId) internal {
        Task storage task = tasks[taskId];
        uint256 total = task.reward;
        uint256 toTreasury = (total * TREASURY_BPS) / 10000;
        uint256 toContributor = (total * CONTRIBUTOR_BPS) / 10000;

        workToken.transfer(treasury, toTreasury);
        workToken.transfer(task.assignee, toContributor);

        emit TaskVerified(taskId, task.assignee, toContributor);
    }

    function setTreasury(address treasury_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        treasury = treasury_;
    }

    function setVerifier(address verifier) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _grantRole(VERIFIER_ROLE, verifier);
    }

    function pause() external onlyRole(PAUSER_ROLE) { _pause(); }
    function unpause() external onlyRole(PAUSER_ROLE) { _unpause(); }
}

contracts/tokens/WorkToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

/**
 * @title WorkToken
 * @notice Utility token pegged 1:1 to USDC. Used for task settlement and agent staking.
 *         Minted when USDC is deposited, burned when redeemed or slashed.
 */
contract WorkToken is ERC20, AccessControl, Pausable {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");

    event Minted(address indexed to, uint256 amount);
    event Burned(address indexed from, uint256 amount);
    event Slashed(address indexed agent, uint256 amount, string reason);

    constructor(address admin) ERC20("WORK Token", "WORK") {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(PAUSER_ROLE, admin);
    }

    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) whenNotPaused {
        _mint(to, amount);
        emit Minted(to, amount);
    }

    function burn(address from, uint256 amount) external onlyRole(BURNER_ROLE) whenNotPaused {
        _burn(from, amount);
        emit Burned(from, amount);
    }

    function slash(address agent, uint256 amount, string calldata reason)
        external
        onlyRole(BURNER_ROLE)
        whenNotPaused
    {
        _burn(agent, amount);
        emit Slashed(agent, amount, reason);
    }

    function pause() external onlyRole(PAUSER_ROLE) { _pause(); }
    function unpause() external onlyRole(PAUSER_ROLE) { _unpause(); }

    function _beforeTokenTransfer(address from, address to, uint256 amount) internal override whenNotPaused {
        super._beforeTokenTransfer(from, to, amount);
    }
}

contracts/verification/OptimisticChallen.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "../tokens/WorkToken.sol";
import "../market/TaskMarket.sol";
import "../identity/DIDRegistry.sol";

/**
 * @title OptimisticChallenge
 * @notice 7-day challenge window for disputed tasks.
 *         Challengers stake WORK tokens. Successful challenges earn from slashed stake.
 *         Core Members arbitrate unresolved challenges.
 */
contract OptimisticChallenge is AccessControl, ReentrancyGuard {
    bytes32 public constant ARBITRATOR_ROLE = keccak256("ARBITRATOR_ROLE");

    uint256 public constant CHALLENGE_PERIOD = 7 days;
    uint256 public constant CHALLENGER_STAKE = 50 * 1e18;

    // Slashing basis points
    uint256 public constant SLASH_MALICIOUS_BPS = 5000;  // 50%
    uint256 public constant SLASH_NEGLIGENT_BPS = 2000;  // 20%

    WorkToken public immutable workToken;
    TaskMarket public immutable taskMarket;
    DIDRegistry public immutable didRegistry;

    struct Challenge {
        uint256 taskId;
        address challenger;
        uint256 challengerStake;
        uint256 openedAt;
        bool resolved;
        bool challengerWon;
        string evidenceHash;
    }

    mapping(uint256 => Challenge) public challenges;
    uint256 public challengeCount;

    event ChallengeOpened(uint256 indexed challengeId, uint256 indexed taskId, address challenger);
    event ChallengeResolved(uint256 indexed challengeId, bool challengerWon, address arbitrator);
    event ChallengExpired(uint256 indexed challengeId, uint256 indexed taskId);

    constructor(address workToken_, address taskMarket_, address didRegistry_, address admin) {
        workToken = WorkToken(workToken_);
        taskMarket = TaskMarket(taskMarket_);
        didRegistry = DIDRegistry(didRegistry_);
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ARBITRATOR_ROLE, admin);
    }

    function openChallenge(uint256 taskId, string calldata evidenceHash)
        external
        nonReentrant
        returns (uint256 challengeId)
    {
        require(didRegistry.isValid(msg.sender), "Invalid DID");
        workToken.transferFrom(msg.sender, address(this), CHALLENGER_STAKE);

        challengeId = ++challengeCount;
        challenges[challengeId] = Challenge({
            taskId: taskId,
            challenger: msg.sender,
            challengerStake: CHALLENGER_STAKE,
            openedAt: block.timestamp,
            resolved: false,
            challengerWon: false,
            evidenceHash: evidenceHash
        });

        emit ChallengeOpened(challengeId, taskId, msg.sender);
    }

    function resolveChallenge(uint256 challengeId, bool challengerWon, bool /* isMalicious */)
        external
        onlyRole(ARBITRATOR_ROLE)
        nonReentrant
    {
        Challenge storage challenge = challenges[challengeId];
        require(!challenge.resolved, "Already resolved");
        require(
            block.timestamp <= challenge.openedAt + CHALLENGE_PERIOD,
            "Challenge period expired"
        );

        challenge.resolved = true;
        challenge.challengerWon = challengerWon;

        if (challengerWon) {
            // Return challenger stake + reward from task agent's slashed stake
            workToken.transfer(challenge.challenger, challenge.challengerStake);
            taskMarket.settleDispute(challenge.taskId, false);
            // Credit challenger's DID for valid challenge
            didRegistry.updateCredit(challenge.challenger, 2);
        } else {
            // Challenger loses stake — burned
            workToken.slash(address(this), challenge.challengerStake, "Failed challenge stake");
            taskMarket.settleDispute(challenge.taskId, true);
            // Penalise challenger's credit score
            didRegistry.updateCredit(challenge.challenger, -1);
        }

        emit ChallengeResolved(challengeId, challengerWon, msg.sender);
    }

    function expireChallenge(uint256 challengeId) external nonReentrant {
        Challenge storage challenge = challenges[challengeId];
        require(!challenge.resolved, "Already resolved");
        require(
            block.timestamp > challenge.openedAt + CHALLENGE_PERIOD,
            "Challenge period not over"
        );

        challenge.resolved = true;
        // No challenge submitted or expired: default pass, return stake
        workToken.transfer(challenge.challenger, challenge.challengerStake);
        taskMarket.settleDispute(challenge.taskId, true);

        emit ChallengExpired(challengeId, challenge.taskId);
    }

    function addArbitrator(address arbitrator) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _grantRole(ARBITRATOR_ROLE, arbitrator);
    }
}

